1	import React, { useState } from 'react';
2	import { ktpApi } from '../../api/ktp.api';
3	import { KnowledgeComponent, BankCoverage, BankItem } from '../../types/ktp.types';
4	import { Button } from '../ui/Button';
5	import { ConfirmDeleteBtn } from '../ui/ConfirmDeleteBtn';
6	import { useAuth } from '../../store/auth.store';
7	import { getApiErrorMessage } from '../../utils/error';
8	
9	/**
10	 * Per-topic блок «Подтемы (KC) и банк вопросов» для экрана КТП.
11	 * Лениво грузится при разворачивании. Мутации (предложить/подтвердить/удалить KC, генерация,
12	 * просмотр вопросов с ответами) — только для admin; teacher видит список/покрытие read-only.
13	 */
14	
15	interface Props {
16	  subjectId: string;
17	  topicId: string;
18	}
19	
20	export const TopicKnowledgeBank: React.FC<Props> = ({ subjectId, topicId }) => {
21	  const { user } = useAuth();
22	  const canEdit = user?.role === 'admin';
23	
24	  const [open, setOpen] = useState(false);
25	  const [loaded, setLoaded] = useState(false);
26	  const [loading, setLoading] = useState(false);
27	  const [err, setErr] = useState<string | null>(null);
28	  const [msg, setMsg] = useState<string | null>(null);
29	
30	  const [kcs, setKcs] = useState<KnowledgeComponent[]>([]);
31	  const [coverage, setCoverage] = useState<BankCoverage | null>(null);
32	  const [sel, setSel] = useState<string[]>([]);
33	
34	  const [proposing, setProposing] = useState(false);
35	  const [confirming, setConfirming] = useState(false);
36	  const [generating, setGenerating] = useState(false);
37	  const [minPerKc, setMinPerKc] = useState(3);
38	  const [difficulty, setDifficulty] = useState(3);
39	
40	  const [addOpen, setAddOpen] = useState(false);
41	  const [addTitle, setAddTitle] = useState('');
42	
43	  const [items, setItems] = useState<BankItem[] | null>(null);
44	  const [loadingItems, setLoadingItems] = useState(false);
45	
46	  const flash = (m: string): void => {
47	    setMsg(m);
48	    setTimeout(() => setMsg(null), 3500);
49	  };
50	
51	  const load = async (): Promise<void> => {
52	    setLoading(true);
53	    setErr(null);
54	    try {
55	      const [kc, cov] = await Promise.all([
56	        ktpApi.listComponents(subjectId, topicId),
57	        ktpApi.bankCoverage(subjectId, topicId)
58	      ]);
59	      setKcs(kc);
60	      setCoverage(cov);
61	      setLoaded(true);
62	    } catch (e) {
63	      setErr(getApiErrorMessage(e));
64	    } finally {
65	      setLoading(false);
66	    }
67	  };
68	
69	  const reloadCoverage = async (): Promise<void> => {
70	    try {
71	      setCoverage(await ktpApi.bankCoverage(subjectId, topicId));
72	    } catch {
73	      /* покрытие не критично — молча */
74	    }
75	  };
76	
77	  const toggle = (): void => {
78	    const next = !open;
79	    setOpen(next);
80	    if (next && !loaded) void load();
81	  };
82	
83	  const runMutation = async (fn: () => Promise<void>): Promise<void> => {
84	    setErr(null);
85	    try {
86	      await fn();
87	    } catch (e) {
88	      setErr(getApiErrorMessage(e));
89	    }
90	  };
91	
92	  const propose = (): Promise<void> =>
93	    runMutation(async () => {
94	      setProposing(true);
95	      try {
96	        setKcs(await ktpApi.proposeComponents(subjectId, topicId));
97	        flash('ИИ предложил подтемы — отметьте нужные и подтвердите');
98	      } finally {
99	        setProposing(false);
100	      }
101	    });
102	
103	  const confirmSelected = (): Promise<void> =>
104	    runMutation(async () => {
105	      if (sel.length === 0) return;
106	      setConfirming(true);
107	      try {
108	        setKcs(await ktpApi.confirmComponents(subjectId, topicId, sel));
109	        setSel([]);
110	        await reloadCoverage();
111	        flash('Подтемы подтверждены');
112	      } finally {
113	        setConfirming(false);
114	      }
115	    });
116	
117	  const removeKc = (kcId: string): Promise<void> =>
118	    runMutation(async () => {
119	      setKcs(await ktpApi.deleteComponent(subjectId, topicId, kcId));
120	      setSel((s) => s.filter((id) => id !== kcId));
121	      await reloadCoverage();
122	      flash('Подтема удалена');
123	    });
124	
125	  const addManual = (): Promise<void> =>
126	    runMutation(async () => {
127	      const title = addTitle.trim();
128	      if (!title) return;
129	      setKcs(await ktpApi.upsertComponent(subjectId, topicId, { title, status: 'confirmed' }));
130	      setAddTitle('');
131	      setAddOpen(false);
132	      await reloadCoverage();
133	      flash('Подтема добавлена');
134	    });
135	
136	  const generate = (): Promise<void> =>
137	    runMutation(async () => {
138	      setGenerating(true);
139	      try {
140	        const res = await ktpApi.bankGenerate(subjectId, topicId, { minPerKc, difficulty });
141	        setCoverage(res.coverage);
142	        setItems(null); // список вопросов устарел
143	        flash(`Сгенерировано: +${res.created}, отклонено судьёй: ${res.rejected}`);
144	      } finally {
145	        setGenerating(false);
146	      }
147	    });
148	
149	  const showItems = (): Promise<void> =>
150	    runMutation(async () => {
151	      setLoadingItems(true);
152	      try {
153	        setItems(await ktpApi.bankItems(subjectId, topicId));
154	      } finally {
155	        setLoadingItems(false);
156	      }
157	    });
158	
159	  const activeByKc = new Map<string, number>();
160	  for (const p of coverage?.perKc ?? []) activeByKc.set(p.kcId, p.active);
161	
162	  const confirmedKcs = kcs.filter((k) => k.status === 'confirmed');
163	  const proposedKcs = kcs.filter((k) => k.status === 'proposed');
164	
165	  return (
166	    <div className="mt-1 border-t border-slate-100 pt-1.5">
167	      <button
168	        onClick={toggle}
169	        className="text-xs font-medium text-blue-600 hover:underline"
170	        title="Подтемы (KC) и банк вопросов"
171	      >
172	        {open ? '▾' : '▸'} Подтемы (KC) и банк
173	        {coverage ? <span className="ml-1 text-slate-400">· {coverage.totalActive} вопр.</span> : null}
174	      </button>
175	
176	      {open && (
177	        <div className="mt-2 space-y-3 rounded-lg bg-slate-50 p-3">
178	          {loading && <p className="text-xs text-slate-500">Загрузка…</p>}
179	          {err && <p className="text-xs text-red-600">{err}</p>}
180	          {msg && <p className="text-xs text-green-700">{msg}</p>}
181	
182	          {/* ── KC: подтверждённые ── */}
183	          {confirmedKcs.length > 0 && (
184	            <div>
185	              <p className="mb-1 text-[11px] font-semibold uppercase tracking-wide text-slate-400">
186	                Подтверждённые подтемы
187	              </p>
188	              <ul className="space-y-1">
189	                {confirmedKcs.map((k) => {
190	                  const active = activeByKc.get(k._id) ?? 0;
191	                  const deficit = active < minPerKc;
192	                  return (
193	                    <li key={k._id} className="flex items-center gap-2 text-sm">
194	                      <span className="text-slate-700">{k.title}</span>
195	                      <span
196	                        className={`rounded px-1.5 py-0.5 text-[11px] ${
197	                          deficit ? 'bg-amber-100 text-amber-700' : 'bg-green-100 text-green-700'
198	                        }`}
199	                        title="активных вопросов в банке"
200	                      >
201	                        {active} вопр.
202	                      </span>
203	                      {canEdit && <ConfirmDeleteBtn onConfirm={() => removeKc(k._id)} />}
204	                    </li>
205	                  );
206	                })}
207	              </ul>
208	            </div>
209	          )}
210	
211	          {/* ── KC: предложенные (ожидают подтверждения) ── */}
212	          {proposedKcs.length > 0 && (
213	            <div>
214	              <p className="mb-1 text-[11px] font-semibold uppercase tracking-wide text-slate-400">
215	                Предложено ИИ — выберите и подтвердите
216	              </p>
217	              <ul className="space-y-1">
218	                {proposedKcs.map((k) => (
219	                  <li key={k._id} className="flex items-center gap-2 text-sm">
220	                    {canEdit && (
221	                      <input
222	                        type="checkbox"
223	                        checked={sel.includes(k._id)}
224	                        onChange={(e) =>
225	                          setSel((s) => (e.target.checked ? [...s, k._id] : s.filter((id) => id !== k._id)))
226	                        }
227	                      />
228	                    )}
229	                    <span className="text-slate-600">{k.title}</span>
230	                    {canEdit && <ConfirmDeleteBtn onConfirm={() => removeKc(k._id)} />}
231	                  </li>
232	                ))}
233	              </ul>
234	              {canEdit && (
235	                <Button
236	                  variant="secondary"
237	                  className="mt-2 !px-3 !py-1 !text-xs"
238	                  isLoading={confirming}
239	                  disabled={sel.length === 0}
240	                  onClick={() => void confirmSelected()}
241	                >
242	                  Подтвердить выбранные ({sel.length})
243	                </Button>
244	              )}
245	            </div>
246	          )}
247	
248	          {loaded && kcs.length === 0 && (
249	            <p className="text-xs text-slate-500">Подтем пока нет. Предложите их ИИ или добавьте вручную.</p>
250	          )}
251	
252	          {/* ── действия с KC ── */}
253	          {canEdit && (
254	            <div className="flex flex-wrap items-center gap-2">
255	              <Button variant="outline" className="!px-3 !py-1 !text-xs" isLoading={proposing} onClick={() => void propose()}>
256	                Предложить KC (ИИ)
257	              </Button>
258	              {addOpen ? (
259	                <span className="inline-flex items-center gap-1.5">
260	                  <input
261	                    autoFocus
262	                    value={addTitle}
263	                    onChange={(e) => setAddTitle(e.target.value)}
264	                    onKeyDown={(e) => {
265	                      if (e.key === 'Enter') void addManual();
266	                      if (e.key === 'Escape') setAddOpen(false);
267	                    }}
268	                    placeholder="Название подтемы"
269	                    className="w-56 rounded border border-slate-300 px-2 py-1 text-xs focus:border-blue-400 focus:outline-none"
270	                  />
271	                  <button onClick={() => void addManual()} className="text-xs font-medium text-blue-600 hover:underline">
272	                    OK
273	                  </button>
274	                  <button onClick={() => setAddOpen(false)} className="text-xs text-slate-400 hover:underline">
275	                    Отмена
276	                  </button>
277	                </span>
278	              ) : (
279	                <button
280	                  onClick={() => setAddOpen(true)}
281	                  className="rounded-lg border border-dashed border-slate-300 px-3 py-1 text-xs text-slate-500 hover:border-blue-300 hover:text-blue-600"
282	                >
283	                  + добавить вручную
284	                </button>
285	              )}
286	            </div>
287	          )}
288	
289	          {/* ── покрытие + генерация банка ── */}
290	          {coverage && (
291	            <div className="rounded-lg border border-slate-200 bg-white p-2.5">
292	              <p className="text-xs text-slate-600">
293	                В банке: <b>{coverage.totalActive}</b> активных вопросов
294	                {coverage.unassigned > 0 ? `, из них вне подтем: ${coverage.unassigned}` : ''}
295	              </p>
296	              {canEdit && (
297	                <div className="mt-2 flex flex-wrap items-center gap-2">
298	                  <label className="text-xs text-slate-500">
299	                    мин/KC{' '}
300	                    <input
301	                      type="number"
302	                      min={1}
303	                      max={20}
304	                      value={minPerKc}
305	                      onChange={(e) => setMinPerKc(Math.max(1, Math.min(20, Number(e.target.value) || 1)))}
306	                      className="w-14 rounded border border-slate-300 px-1.5 py-0.5 text-xs"
307	                    />
308	                  </label>
309	                  <label className="text-xs text-slate-500">
310	                    сложн.{' '}
311	                    <input
312	                      type="number"
313	                      min={1}
314	                      max={5}
315	                      value={difficulty}
316	                      onChange={(e) => setDifficulty(Math.max(1, Math.min(5, Number(e.target.value) || 3)))}
317	                      className="w-14 rounded border border-slate-300 px-1.5 py-0.5 text-xs"
318	                    />
319	                  </label>
320	                  <Button
321	                    variant="primary"
322	                    className="!px-3 !py-1 !text-xs"
323	                    isLoading={generating}
324	                    onClick={() => void generate()}
325	                    title="Генерация дёргает ИИ и может занять время"
326	                  >
327	                    Сгенерировать банк
328	                  </Button>
329	                </div>
330	              )}
331	            </div>
332	          )}
333	
334	          {/* ── просмотр сгенерированных вопросов ── */}
335	          {canEdit && (
336	            <div>
337	              <Button variant="ghost" className="!px-2 !py-1 !text-xs" isLoading={loadingItems} onClick={() => void showItems()}>
338	                {items ? 'Обновить вопросы' : 'Показать вопросы'}
339	              </Button>
340	              {items && items.length === 0 && <p className="mt-1 text-xs text-slate-500">Вопросов пока нет.</p>}
341	              {items && items.length > 0 && (
342	                <ol className="mt-2 space-y-2">
343	                  {items.map((it) => (
344	                    <li key={it._id} className="rounded-lg border border-slate-200 bg-white p-2.5 text-sm">
345	                      <div className="flex items-start justify-between gap-2">
346	                        <p className="font-medium text-slate-800">{it.question.questionText}</p>
347	                        <span className="shrink-0 text-[11px] text-slate-400">
348	                          ур.{it.difficulty} · {it.status}
349	                        </span>
350	                      </div>
351	                      <ul className="mt-1 space-y-0.5">
352	                        {(it.question.options ?? []).map((opt, i) => {
353	                          const correct = opt === it.question.correctOption;
354	                          return (
355	                            <li
356	                              key={i}
357	                              className={`text-xs ${correct ? 'font-medium text-green-700' : 'text-slate-600'}`}
358	                            >
359	                              {correct ? '✓ ' : '• '}
360	                              {opt}
361	                            </li>
362	                          );
363	                        })}
364	                      </ul>
365	                      {it.question.aiExplanation && (
366	                        <p className="mt-1 text-[11px] italic text-slate-400">{it.question.aiExplanation}</p>
367	                      )}
368	                      <div className="mt-1 flex items-center gap-2 text-[11px] text-slate-300">
369	                        <span>
370	                          показов {it.qualityStats?.timesUsed ?? 0} · верных {it.qualityStats?.timesCorrect ?? 0}
371	                        </span>
372	                        {/* TODO Phase A-next: включить правку/ретайр/удаление item'а */}
373	                        <button disabled className="cursor-not-allowed text-slate-300" title="скоро">
374	                          Править
375	                        </button>
376	                        <button disabled className="cursor-not-allowed text-slate-300" title="скоро">
377	                          Ретайр
378	                        </button>
379	                        <button disabled className="cursor-not-allowed text-slate-300" title="скоро">
380	                          Удалить
381	                        </button>
382	                      </div>
383	                    </li>
384	                  ))}
385	                </ol>
386	              )}
387	            </div>
388	          )}
389	        </div>
390	      )}
391	    </div>
392	  );
393	};
394
